import json

business_file = '/tmp/tmp0n6o0v8a.json'
with open(business_file, 'r') as f:
    businesses = json.load(f)

business_states = []
for business in businesses:
    description = business.get('description', '')
    state = None

    if ' in ' in description:
        parts = description.split(' in ')
        if len(parts) > 1:
            location = parts[-1]
            if ', ' in location:
                city_state = location.split(', ')
                if len(city_state) > 1:
                    potential_state = city_state[-1].strip()
                    if len(potential_state) >= 2:
                        state_code = potential_state[:2]
                        if state_code.isupper():
                            state = state_code

    if state:
        business_states.append({
            'business_id': business['business_id'],
            'state': state,
            'review_count': int(business['review_count'])
        })

# Group by state
from collections import defaultdict
state_totals = defaultdict(lambda: {'total_reviews': 0, 'businesses': []})
for b in business_states:
    state_totals[b['state']]['total_reviews'] += b['review_count']
    state_totals[b['state']]['businesses'].append(b['business_id'])

# Find state with highest reviews
max_state = max(state_totals.items(), key=lambda x: x[1]['total_reviews'])

result = {
    'state': max_state[0],
    'total_reviews': max_state[1]['total_reviews'],
    'business_count': len(max_state[1]['businesses'])
}

print('__RESULT__:')
print(json.dumps(result))

